# EVOLVE-BLOCK-START
"""25 large circles on a 5x5 grid plus one smaller circle in an interior gap."""
import numpy as np


def construct_packing():
    eps = 1e-9
    xs = np.array([0.1, 0.3, 0.5, 0.7, 0.9], float)
    centers = np.array([(x, y) for y in xs for x in xs] + [(0.4, 0.4)], float)
    radii = np.array([0.1 - eps] * 25 + [np.sqrt(0.02) - 0.1 - eps], float)
    return centers, radii, float(radii.sum())
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    _, _, s = run_packing()
    print(f"Sum of radii: {s:.6f}")
